[Werner-Young's inequality]\label{Young op-op}
Suppose $S\in \cS^p$ and $T\in \cS^q$ with $1+r^{-1}=p^{-1}+q^{-1}$.
Then $S\star T\in L^r(\R^{2d})$ and
\begin{align*}
    \|S\star T\|_{L^{r}}\leq \|S\|_{\cS^p}\|T\|_{\cS^q}.
\end{align*}

\label{Corollary}
     Let Assumptions~\ref{assum_1} and~\ref{assump2} be satisfied. Let $u$ be the solution of~\eqref{WeakForm} and let $u_{H,k}$ be the LOD solution of~\eqref{local_probelm }. Then we have 
     \begin{equation}\label{L2Estimate}
         \|u-I_Hu_{H,k}\|_0\lesssim  \|u-I_Hu\|_0+\|u-u_{H,k}\|_0 +H|u-u_{H,k}|_1.
     \end{equation}
     %\[\|u-I_Hu_{H,k}\|_0\lesssim H |u|_1 +|u-u_{H,k}|_1.\]

\label{lem1}
		For all $m,j\in\Z$,  we have
		\begin{equation*}
		|| T_{m,j} (E)-T_{m+k_n,j+k_n}(E)||\leq C e^{-\gamma  k_n}  e^{(\mathcal L(E)+\varepsilon) |m-j|}. 
		\end{equation*}

\label{RL1}
The system \eqref{R3} has the following positive fixed points if $0 <\alpha\leq1$ and $b>d$
$$E^*=\left(\dfrac{d}{b}, \dfrac{(b-d) r}{b^2}\right)$$

For any $\lambda \in(0,1)$ and $s \in\mathbb N$,
  \begin{equation*}
\sum_{k=s}^{\infty}\binom {k}{s}
(1-\lambda)^{k-s}=    \lambda^{-s-1}.
\end{equation*}

\label{convergence-rates}
Under the assumptions of Theorem~\ref{well-posedness}. Given $(\bu,{p},\bzeta,\varphi)\in (\bH^{s_1+1}(\Omega)\cap \bV_1)\times (\text{H}^{s_1}(\Omega)\cap Q_{b_1}) \times (\bH^{s_2}\cap \bV_2) \times (\text{H}^{s_2}\cap Q_{b_2})$, $(\bu_h,{p}_h,\bzeta_h,\varphi_h)\in \bV_1^{h,k_1}\times Q_1^{h,k_1}\times \bV_2^{h,k_2}\times Q_2^{h,k_2}$ be the respective solutions of the continuous and discrete problems, with the data satisfying $\fb\in \bH^{s_1-1}\cap \bQ_{b_1}$ and $g\in H^{s_2}(\Omega)\cap Q_{b_2}$. If $\overline{C}_1 \sqrt{M} L_\ell + \overline{C}_2^2 \sqrt{M^3} L_\bbM\sqrt{2\mu}   (\norm{\varphi_D}_{1/2,\Gamma_D} + \norm{g}_{0,\Omega}) < 1/2.$ Then, the total error $\overline{\textnormal{e}}_h:=\norm{(\bu-\bu_h,{p}-{p}_h, \bzeta-\bzeta_h,\varphi-\varphi_h)}_{\bV_1\times Q_{1} \times \bV_2\times Q_2}$ decays with the following rate for $s:= \min \left\{s_1,s_2\right\}$
    \begin{align*}\label{convergence-rate}
         \overline{\textnormal{e}}_h &\lesssim h^{ s} (|\fb|_{s_1-1,\bQ_{b_1}} + |\bu|_{s_1+1,\bV_1} + |{p}|_{s_1,Q_{b_1}} + |g|_{s_2,Q_{b_2}} + |\bzeta|_{s_2,\bV_2}+|\varphi|_{s_2,Q_{b_2}}).
    \end{align*}

(\cite{DangWangXieZhou})\label{Theorem_Error_Estimate_k}
Let us define the spectral projection $F_{k,h}^{(\ell)}: V\mapsto {\rm span}\{u_{1,h}^{(\ell)}, \cdots, u_{k,h}^{(\ell)}\}$ for any integer $\ell \geq 1$ as follows:
\begin{eqnarray*}
a(F_{k,h}^{(\ell)}w, u_{i,h}^{(\ell)}) = a(w, u_{i,h}^{(\ell)}), \ \ \ i=1, \cdots, k\ \ {\rm for}\ w\in V.
\end{eqnarray*}
Then the exact eigenfunctions $\bar u_{1,h},\cdots, \bar u_{k,h}$ of (\ref{Weak_Eigenvalue_Discrete}) and the eigenfunction approximations $u_{1,h}^{(\ell+1)}$, $\cdots$,  $u_{k,h}^{(\ell+1)}$ from Algorithm \ref{Algorithm_k} with the integer $\ell > 1$ have the following error estimate:
\begin{eqnarray*}\label{Error_Estimate_Inverse}
 \left\|\bar u_{i,h} - F_{k,h}^{(\ell+1)}\bar u_{i,h} \right\|_a \leq
 \bar\lambda_{i,h} \sqrt{1+\frac{\eta_a^2(V_H)}{\bar\lambda_{1,h}\big(\delta_{k,i,h}^{(\ell+1)}\big)^2}}
\left(1+\frac{\bar\mu_{1,h}}{\delta_{k,i,h}^{(\ell)}}\right)\eta_a^2(V_H)\left\|\bar u_{i,h} - F_{k,h}^{(\ell)}\bar u_{i,h} \right\|_a,
\end{eqnarray*}
where $\delta_{k,i,h}^{(\ell)} $ is defined as follows:
\begin{eqnarray*}
\delta_{k,i,h}^{(\ell)} = \min_{j\not\in \{1, \cdots, k\}}\left|\frac{1}{\lambda_{j,h}^{(\ell)}}-\frac{1}{\bar\lambda_{i,h}}\right|,\ \ \ i=1, \cdots, k.
\end{eqnarray*}
Furthermore, the following $\left\|\cdot\right\|_b$-norm error estimate holds:
\begin{eqnarray*}
\left\|\bar u_{i,h} -F_{k,h}^{(\ell+1)}\bar u_{i,h} \right\|_b\leq 
\left(1+\frac{\bar\mu_{1,h}}{\delta_{k,i,h}^{(\ell+1)}}\right)\eta_a(V_H) \left\|\bar u_{i,h} -F_{k,h}^{(\ell+1)}\bar u_{i,h}\right\|_a.
\end{eqnarray*}

